export const KNOWLEDGE_CSS_SOURCE = String.raw`:root{--kn-blue:#2563eb;--kn-navy:#0f172a;--kn-ink:#172033;--kn-muted:#667085;--kn-line:#dfe5ee;--kn-soft:#f5f7fb;--kn-white:#fff;--kn-radius:26px}.mmg-knowledge{color:var(--kn-ink);font-family:var(--font-body-family,system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif)}.mmg-knowledge *{box-sizing:border-box}.mmg-knowledge h1,.mmg-knowledge h2,.mmg-knowledge h3{font-family:var(--font-heading-family,var(--font-body-family,system-ui));letter-spacing:-.04em;color:var(--kn-ink);margin-top:0}.mmg-knowledge h1{font-size:clamp(3.6rem,7.2vw,7rem);line-height:.96;max-width:10ch;margin-bottom:1.5rem}.mmg-knowledge h2{font-size:clamp(2.5rem,5vw,4.6rem);line-height:1.02}.mmg-knowledge h3{font-size:clamp(1.4rem,2.2vw,1.95rem);line-height:1.14}.mmg-knowledge p{font-size:1.1rem;line-height:1.72;color:var(--kn-muted)}.knowledge-shell{width:min(1220px,calc(100% - 48px));margin:auto}.knowledge-hero{padding:clamp(5.5rem,9vw,8.5rem) 0;background:linear-gradient(180deg,#fff,#f7f9fc);border-bottom:1px solid var(--kn-line)}.knowledge-hero__grid,.knowledge-split{display:grid;grid-template-columns:1.15fr .85fr;gap:clamp(3rem,7vw,7rem);align-items:center}.knowledge-lead{font-size:clamp(1.35rem,2.4vw,1.85rem)!important;color:var(--kn-ink)!important;max-width:850px}.knowledge-eyebrow{display:inline-flex;font-size:.82rem!important;font-weight:850;letter-spacing:.13em;text-transform:uppercase;color:var(--kn-blue)!important;background:#eaf1ff;border-radius:999px;padding:.68rem .95rem}.knowledge-actions{display:flex;flex-wrap:wrap;gap:.8rem;margin-top:2rem}.knowledge-actions--center{justify-content:center}.knowledge-button{display:inline-flex;align-items:center;justify-content:center;min-height:56px;padding:.9rem 1.5rem;border:1px solid var(--kn-line);border-radius:999px;background:#fff;color:var(--kn-ink);font-weight:820;text-decoration:none}.knowledge-button--primary{background:var(--kn-blue);border-color:var(--kn-blue);color:#fff}.knowledge-summary{background:#fff;border:1px solid var(--kn-line);border-radius:32px;padding:2.4rem;box-shadow:0 20px 60px rgba(15,23,42,.09)}.knowledge-summary>span,.knowledge-card>span,.knowledge-grid--pathways article>span{font-size:.8rem;font-weight:850;letter-spacing:.09em;text-transform:uppercase;color:var(--kn-blue)}.knowledge-section{padding:clamp(5.5rem,9vw,8.5rem) 0}.knowledge-section--soft{background:var(--kn-soft);border-block:1px solid var(--kn-line)}.knowledge-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:1.2rem;margin-top:3rem}.knowledge-grid--pathways{grid-template-columns:repeat(2,1fr)}.knowledge-grid article,.knowledge-card{background:#fff;border:1px solid var(--kn-line);border-radius:var(--kn-radius);padding:2rem;min-height:315px;display:flex;flex-direction:column}.knowledge-card--feature{grid-column:span 2;background:linear-gradient(145deg,#eff5ff,#fff)}.knowledge-grid a{margin-top:auto;color:var(--kn-blue);font-weight:820;text-decoration:none}.knowledge-steps{display:grid;gap:.85rem}.knowledge-steps article{display:grid;grid-template-columns:52px 1fr;gap:1rem;background:#fff;border:1px solid var(--kn-line);border-radius:20px;padding:1.2rem}.knowledge-steps b{color:var(--kn-blue)}.knowledge-steps h3{font-size:1.25rem;margin-bottom:.25rem}.knowledge-steps p{font-size:1rem;margin:0}.knowledge-section--dark{background:linear-gradient(145deg,#1d4ed8,#0f172a)}.knowledge-section--dark h2,.knowledge-section--dark p{color:#fff}.knowledge-section--dark .knowledge-eyebrow{background:rgba(255,255,255,.14);color:#fff!important}.knowledge-kairos{display:grid;gap:.85rem}.knowledge-kairos article{background:rgba(255,255,255,.1);border:1px solid rgba(255,255,255,.16);border-radius:18px;padding:1.2rem}.knowledge-kairos strong,.knowledge-kairos span{display:block;color:#fff}.knowledge-kairos span{font-size:.88rem;margin-top:.25rem;opacity:.76}.knowledge-final{text-align:center;padding:clamp(5.5rem,9vw,8.5rem) 0;background:linear-gradient(180deg,#fff,#f7f9fc)}.knowledge-final h2,.knowledge-final>div>p:not(.knowledge-eyebrow){max-width:900px;margin-inline:auto}@media(max-width:900px){.knowledge-hero__grid,.knowledge-split{grid-template-columns:1fr}.knowledge-grid,.knowledge-grid--pathways{grid-template-columns:repeat(2,1fr)}.knowledge-card--feature{grid-column:span 2}}@media(max-width:640px){.knowledge-shell{width:min(100% - 28px,1220px)}.knowledge-grid,.knowledge-grid--pathways{grid-template-columns:1fr}.knowledge-card--feature{grid-column:auto}.mmg-knowledge h1{font-size:clamp(3rem,15vw,4.8rem)}.knowledge-actions .knowledge-button{width:100%}}`;